import{_ as a,o as t,c as r,a5 as n}from"./chunks/framework.B5tqjWbr.js";const u=JSON.parse('{"title":"概念：三电平 NPC 逆变器","description":"","frontmatter":{"date":"2026-06-22T00:00:00.000Z","category":"电源控制","source":"power","visibility":"public","title":"概念：三电平 NPC 逆变器","tags":["power-electronics"],"status":"learning","summary":"本页是 `lessons/0042-three-level-npc-inverter.html` 的源稿。"},"headers":[],"relativePath":"content/power/concepts/power-electronics/three-level-npc-inverter.md","filePath":"content/power/concepts/power-electronics/three-level-npc-inverter.md","lastUpdated":null}'),l={name:"content/power/concepts/power-electronics/three-level-npc-inverter.md"};function s(o,e,i,c,p,h){return t(),r("div",null,[...e[0]||(e[0]=[n(`<h1 id="概念-三电平-npc-逆变器" tabindex="-1">概念：三电平 NPC 逆变器 <a class="header-anchor" href="#概念-三电平-npc-逆变器" aria-label="Permalink to &quot;概念：三电平 NPC 逆变器&quot;">​</a></h1><p>本页是 <code>lessons/0042-three-level-npc-inverter.html</code> 的源稿。</p><h2 id="它是什么" tabindex="-1">它是什么 <a class="header-anchor" href="#它是什么" aria-label="Permalink to &quot;它是什么&quot;">​</a></h2><p>三电平 NPC 逆变器（three-level neutral-point-clamped inverter / NPC inverter）让每相输出 +Vdc/2、0、-Vdc/2 三种电平，降低电压应力和输出谐波。</p><h2 id="为什么-ups-pcs-需要它" tabindex="-1">为什么 UPS/PCS 需要它 <a class="header-anchor" href="#为什么-ups-pcs-需要它" aria-label="Permalink to &quot;为什么 UPS/PCS 需要它&quot;">​</a></h2><p>中大功率 UPS 输出级和 PCS 交流侧常需要低谐波、高效率和较低 EMI。NPC 拓扑是常见三电平方案之一。</p><h2 id="数学形式" tabindex="-1">数学形式 <a class="header-anchor" href="#数学形式" aria-label="Permalink to &quot;数学形式&quot;">​</a></h2><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>P -&gt; +Vdc / 2</span></span>
<span class="line"><span>O -&gt; 0 through neutral clamp</span></span>
<span class="line"><span>N -&gt; -Vdc / 2</span></span></code></pre></div><h2 id="一个仿真任务" tabindex="-1">一个仿真任务 <a class="header-anchor" href="#一个仿真任务" aria-label="Permalink to &quot;一个仿真任务&quot;">​</a></h2><p>比较两电平和三电平相电压阶梯，再观察冗余小矢量对中点电压的影响。</p><h2 id="验收标准" tabindex="-1">验收标准 <a class="header-anchor" href="#验收标准" aria-label="Permalink to &quot;验收标准&quot;">​</a></h2><ul><li>能画出 P/O/N 三种相电平。</li><li>能解释 NPC 为什么降低器件电压应力。</li><li>能说明冗余矢量和中点平衡的关系。</li></ul><h2 id="导师问题" tabindex="-1">导师问题 <a class="header-anchor" href="#导师问题" aria-label="Permalink to &quot;导师问题&quot;">​</a></h2><p>NPC 中点平衡由调制层、外环还是单独控制器处理？</p>`,14)])])}const P=a(l,[["render",s]]);export{u as __pageData,P as default};
